import{_ as l,o as e,c as i,a4 as r}from"./chunks/framework._in6GHBg.js";const h=JSON.parse('{"title":"文言文翻译四步法","description":"","frontmatter":{},"headers":[],"relativePath":"chinese/tip-classical.md","filePath":"chinese/tip-classical.md"}'),n={name:"chinese/tip-classical.md"};function o(a,t,s,g,d,p){return e(),i("div",null,[...t[0]||(t[0]=[r('<h1 id="文言文翻译四步法" tabindex="-1">文言文翻译四步法 <a class="header-anchor" href="#文言文翻译四步法" aria-label="Permalink to &quot;文言文翻译四步法&quot;">​</a></h1><p><strong>从&quot;看不懂&quot;到&quot;翻译准&quot;——攻克文言文翻译题</strong></p><hr><h2 id="痛点" tabindex="-1">痛点 <a class="header-anchor" href="#痛点" aria-label="Permalink to &quot;痛点&quot;">​</a></h2><ul><li>文言词不认识，句子看不懂</li><li>看懂了意思，翻译出来不通顺</li><li>字字对应翻译，但意思不对</li><li>漏译、错译关键词，被扣分</li></ul><hr><h2 id="四步法" tabindex="-1">四步法 <a class="header-anchor" href="#四步法" aria-label="Permalink to &quot;四步法&quot;">​</a></h2><h3 id="第一步-找动词-定主干-1分钟" tabindex="-1">第一步：找动词，定主干（1分钟） <a class="header-anchor" href="#第一步-找动词-定主干-1分钟" aria-label="Permalink to &quot;第一步：找动词，定主干（1分钟）&quot;">​</a></h3><p><strong>做什么</strong>：找出句子中的谓语动词，确定谁做了什么</p><p><strong>方法</strong>：</p><ul><li>找表示动作的词</li><li>确定主语（谁）和宾语（做了什么/什么怎么样）</li></ul><p><strong>示例</strong>：</p><blockquote><p>吾尝终日而思矣，不如须臾之所学也。</p></blockquote><p><strong>找动词</strong>：思、学 <strong>定主干</strong>：</p><ul><li>我思（我思考）</li><li>不如学（不如学习）</li></ul><hr><h3 id="第二步-辨句式-理结构-1分钟" tabindex="-1">第二步：辨句式，理结构（1分钟） <a class="header-anchor" href="#第二步-辨句式-理结构-1分钟" aria-label="Permalink to &quot;第二步：辨句式，理结构（1分钟）&quot;">​</a></h3><p><strong>常见特殊句式</strong>：</p><table tabindex="0"><thead><tr><th style="text-align:center;">句式</th><th style="text-align:center;">标志</th><th style="text-align:left;">翻译方法</th></tr></thead><tbody><tr><td style="text-align:center;"><strong>判断句</strong></td><td style="text-align:center;">...者...也 / 乃、为、即</td><td style="text-align:left;">是</td></tr><tr><td style="text-align:center;"><strong>被动句</strong></td><td style="text-align:center;">于、见、被、为...所</td><td style="text-align:left;">被</td></tr><tr><td style="text-align:center;"><strong>倒装句</strong></td><td style="text-align:center;">宾语前置、状语后置</td><td style="text-align:left;">调整语序</td></tr><tr><td style="text-align:center;"><strong>省略句</strong></td><td style="text-align:center;">省略主语/宾语</td><td style="text-align:left;">补出省略成分</td></tr></tbody></table><p><strong>示例</strong>：</p><blockquote><p>不拘于时。（被动句） 翻译：不被时俗限制。</p></blockquote><blockquote><p>何以战？（宾语前置 = 以何战） 翻译：凭借什么作战？</p></blockquote><hr><h3 id="第三步-译实词-准而信-2分钟" tabindex="-1">第三步：译实词，准而信（2分钟） <a class="header-anchor" href="#第三步-译实词-准而信-2分钟" aria-label="Permalink to &quot;第三步：译实词，准而信（2分钟）&quot;">​</a></h3><p><strong>实词翻译原则</strong>：</p><p><strong>原则1：留</strong></p><ul><li>人名、地名、官名、年号保留不译</li><li>示例：李白、长安、太守、贞观</li></ul><p><strong>原则2：补</strong></p><ul><li>省略成分补出来</li><li>示例：（桃花源中人）见渔人，乃大惊</li></ul><p><strong>原则3：换</strong></p><ul><li>古今异义词换成现代汉语</li><li>示例：走→跑，谢→道歉，卑鄙→身份低微</li></ul><p><strong>原则4：调</strong></p><ul><li>特殊句式调整语序</li><li>示例：何以战→以何战</li></ul><p><strong>高频实词（必背）</strong>：</p><table tabindex="0"><thead><tr><th style="text-align:center;">词</th><th style="text-align:center;">常见义</th><th style="text-align:left;">例句</th></tr></thead><tbody><tr><td style="text-align:center;"><strong>之</strong></td><td style="text-align:center;">的 / 他/她/它 / 去</td><td style="text-align:left;">山川之美 / 执策而临之 / 吾欲之南海</td></tr><tr><td style="text-align:center;"><strong>其</strong></td><td style="text-align:center;">他的/它的 / 那 / 难道</td><td style="text-align:left;">其身正 / 其真无马邪</td></tr><tr><td style="text-align:center;"><strong>而</strong></td><td style="text-align:center;">并且/但是/如果/地</td><td style="text-align:left;">温故而知新 / 人不知而不愠</td></tr><tr><td style="text-align:center;"><strong>以</strong></td><td style="text-align:center;">用/因为/把/来</td><td style="text-align:left;">以刀劈狼首 / 不以物喜</td></tr><tr><td style="text-align:center;"><strong>于</strong></td><td style="text-align:center;">在/到/比/被</td><td style="text-align:left;">战于长勺 / 苛政猛于虎</td></tr></tbody></table><hr><h3 id="第四步-连贯通-达而雅-1分钟" tabindex="-1">第四步：连贯通，达而雅（1分钟） <a class="header-anchor" href="#第四步-连贯通-达而雅-1分钟" aria-label="Permalink to &quot;第四步：连贯通，达而雅（1分钟）&quot;">​</a></h3><p><strong>检查清单</strong>：</p><ul><li>[ ] 每个词都译了吗？</li><li>[ ] 通顺吗？（念一遍）</li><li>[ ] 符合现代汉语习惯吗？</li><li>[ ] 意思对了吗？</li></ul><p><strong>翻译标准</strong>：</p><ul><li><strong>信</strong>：准确（意思对）</li><li><strong>达</strong>：通顺（读得顺）</li><li><strong>雅</strong>：优美（酌情，高考主要考前两个）</li></ul><hr><h2 id="实战演练" tabindex="-1">实战演练 <a class="header-anchor" href="#实战演练" aria-label="Permalink to &quot;实战演练&quot;">​</a></h2><p><strong>例句1</strong>：</p><blockquote><p>师者，所以传道受业解惑也。</p></blockquote><p><strong>四步翻译</strong>：</p><ol><li>找动词：传道、受业、解惑</li><li>辨句式：...者...也（判断句）</li><li>译实词： <ul><li>师：老师</li><li>所以：用来...的</li><li>传道：传授道理</li><li>受业：教授学业</li><li>解惑：解答疑惑</li></ul></li><li>连贯通： <blockquote><p>老师，是用来传授道理、教授学业、解答疑惑的人。</p></blockquote></li></ol><hr><p><strong>例句2</strong>：</p><blockquote><p>蚓无爪牙之利，筋骨之强。</p></blockquote><p><strong>四步翻译</strong>：</p><ol><li>找动词：无</li><li>辨句式：爪牙之利 = 利之爪牙（定语后置）</li><li>译实词： <ul><li>蚓：蚯蚓</li><li>爪牙：爪子和牙齿</li><li>利：锋利</li><li>强：强健</li></ul></li><li>连贯通： <blockquote><p>蚯蚓没有锋利的爪子和牙齿，没有强健的筋骨。</p></blockquote></li></ol><hr><p><strong>例句3</strong>：</p><blockquote><p>句读之不知，惑之不解。</p></blockquote><p><strong>四步翻译</strong>：</p><ol><li>找动词：知、解</li><li>辨句式：句读之不知 = 不知句读（宾语前置）</li><li>译实词： <ul><li>句读：文句停顿</li><li>惑：疑惑</li></ul></li><li>连贯通： <blockquote><p>不懂得文句停顿，不能解决疑惑。</p></blockquote></li></ol><hr><h2 id="采分点提醒" tabindex="-1">采分点提醒 <a class="header-anchor" href="#采分点提醒" aria-label="Permalink to &quot;采分点提醒&quot;">​</a></h2><p>高考翻译题通常按点给分：</p><ul><li>重点实词（1-2分）</li><li>特殊句式（1-2分）</li><li>整体通顺（1分）</li></ul><p><strong>策略</strong>：</p><ul><li>先译会译的，保证得分</li><li>不会的词根据上下文猜</li><li>不要空着，写了可能有分</li></ul><hr><p><strong>文档编号</strong>: Chin-Tip-005<br><strong>版本</strong>: V1.0<br><strong>日期</strong>: 20260405</p>',65)])])}const u=l(n,[["render",o]]);export{h as __pageData,u as default};
